import React, { useState, useEffect } from 'react';
import './UserEditModal.css';
import axios from 'axios';
import { useForm } from 'react-hook-form';

interface User {
  username: string;
  name: string;
  role: string;
  email: string;
  company: string;
  password?: string; // Optional password
}

interface Group {
  active: number;
  group_id: string;
  name: string;
}

interface UserEditModalProps {
  user: User;
  onSave: (user: User) => void;
  onClose: () => void;
  option?: string;
}

const UserEditModal: React.FC<UserEditModalProps> = ({ user, onSave, onClose, option }) => {
  const [formData, setFormData] = useState<User>({
    ...user,
    password: '', // Initialize password field explicitly
  });
  const [confirmPassword, setConfirmPassword] = useState<string>('');
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [isAdmin, setIsAdmin] = useState<boolean>(false);
  const [groups, setGroups] = useState<Group[]>([]);
  const { register, handleSubmit, formState: { errors } } = useForm<User>({
    defaultValues: user
  });

  // Check if the user is an admin
  useEffect(() => {
    const username = localStorage.getItem('username');
    if (username?.toLowerCase() === 'admin') {
      setIsAdmin(true);
    }
  }, []);

  // Synchronize formData with user prop when it changes
  useEffect(() => {
    setFormData({ ...user, password: '' }); // Reset password to an empty value

    setSuccessMessage(null);
    setErrorMessage(null);

  }, [user]);

  useEffect(() => {
    const fetchGroups = async () => {
      try {
        const response = await axios.get<Group[]>('/api/groups');
        setGroups(response.data);
      } catch (error) {
        console.error('Error fetching groups:', error);
      }
    };

    fetchGroups();
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prevState => ({
      ...prevState,
      [name]: value,
    }));
  };

  const handlePasswordChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData(prevState => ({
      ...prevState,
      password: e.target.value,
    }));
  };

  const handleConfirmPasswordChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setConfirmPassword(e.target.value);
  };

  const handleSubmit2 = () => {
    if (formData.password && formData.password !== confirmPassword) {
      alert("Passwords do not match!");
      return;
    }
    try {
      onSave(formData); // Pass updated data back to parent
    }
    catch (error) {
      console.error('Erro ao salvar usuário:', error);
    }
  };

  const handleCancel = () => {
    onClose();
  };

  return (
    <div className="modal-content">
      <div className="modal-actions">
        <button onClick={handleSubmit2}>Gravar</button>
        <button onClick={handleCancel}>Cancelar</button>
      </div>

      <h2>Opção {option}</h2>
      <label>
        Username
        <input
          type="text"
          name="username"
          value={formData.username}
          onChange={handleChange}
          disabled={option === 'Alterar'}
        />
      </label>
      <label>
        Nome
        <input
          type="text"
          name="name"
          value={formData.name}
          onChange={handleChange}
        />
      </label>
      <label>
        <p>Grupo</p>
        <p>
        <select
          {...register("role", { required: "Grupo Obrigatório" })}
          value={formData.role} // Garante que o select reflita o valor atual
          onChange={(e) => setFormData(prevState => ({ ...prevState, role: e.target.value }))} // Atualiza o estado corretamente
        >
          <option value="">Selecione o Grupo</option>
          {groups.map((group) => (
            <option key={group.group_id} value={group.group_id}>
              {group.name}
            </option>
          ))}
          </select>
          </p>
        {errors.role && <span className="error">{errors.role.message}</span>}
      </label>

      <label>
        e-mail
        <input
          type="text"
          name="email"
          value={formData.email}
          onChange={handleChange}
        />
      </label>
      <label>
        Empresa
        <input
          type="text"
          name="company"
          value={formData.company}
          onChange={handleChange}
        />
      </label>
      <div className="password-container">
        <label>
          Senha:
          <input
            type="password"
            name="password"
            value={formData.password}
            onChange={handlePasswordChange}
          />
        </label><label>
          Confirme:
          <input
            type="password"
            name="confirmPassword"
            value={confirmPassword}
            onChange={handleConfirmPasswordChange}
          />
        </label>
      </div>
      <div>
        {successMessage && <div className='successballoon2'>{successMessage}</div>}
        {errorMessage && <div className='failedballoon2'>{errorMessage}</div>}
      </div>
    </div>
  );
};

export default UserEditModal;
