import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import '../Users/UserManagement.css';
import ConfirmationModal from "../ConfirmationModal/ConfirmationModal";

const GroupsManagement = () => {
    interface Group {
        group_id: string;
        name: string;
        active: number;
    }

    const [groups, setGroups] = useState<Group[]>([]);
    const [showModal, setShowModal] = useState(false);
    const [currentGroup, setCurrentGroup] = useState({ group_id: '', name: '', active: 0 });
    const [loading, setLoading] = useState(false);
    const [addingGroup, setAddingGroup] = useState(false);
    const [error, setError] = useState('');
    const [isModalConfirmationOpen, setIsModalConfirmationOpen] = useState<boolean>(false);
    const [modalActionConfirmation, setmodalActionConfirmation] = useState<() => void>(() => { });

    const fetchGroups = useCallback(async () => {
        setLoading(true);
        try {
            const response = await axios.get('/api/groups');
            setGroups(response.data);
        } catch (error) {
            console.error('Error fetching groups:', error);
            setError('Error fetching groups');
        } finally {
            setLoading(false);
        }
    }, []);

    const showModalConfirmation = (action: () => void) => {
        setmodalActionConfirmation(() => action);
        setIsModalConfirmationOpen(true);
      };
    
    useEffect(() => {
        fetchGroups();
    }, [fetchGroups]);

    const cancelAction = () => {
        setIsModalConfirmationOpen(false);
    };

    const confirmAction = () => {
        modalActionConfirmation();
    };
    
    const handleSaveGroup = async () => {
        setLoading(true);
        try {
            if (currentGroup.group_id && !addingGroup) {
                await axios.put(`/api/groups/${currentGroup.group_id}`, currentGroup);
            } else {
                await axios.post('/api/groups', currentGroup);
            }
            fetchGroups();
            setShowModal(false);
        } catch (error) {
            console.error('Error saving group:', error);
            setError('Error saving group');
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteGroup = async (group_id: string): Promise<void> => {
        showModalConfirmation(() => {
            try {
                axios.delete(`/api/groups/${group_id}`);
                fetchGroups();
            } catch (error) {
                console.error('Error deleting group:', error);
                setError('Error deleting group');
            } finally {
                setIsModalConfirmationOpen(false);
                fetchGroups();
            }
        })
    };

    return (
        <div className="user-management">
            <h3>Grupos</h3>
            {error && <div className="alert alert-danger">{error}</div>}
            <button className="add-user-button" onClick={() => { setCurrentGroup({ group_id: '', name: '', active: 0 }); setAddingGroup(true); setShowModal(true); }}>Incluir</button>

            {loading ? <div className="user-management" role="status"><span className="sr-only">Loading...</span></div> : (
                <table className="user-table">
                    <thead>
                        <tr>
                            <th>Grupo</th>
                            <th>Nome</th>
                            <th>Ativo</th>
                            <th>Ações</th>
                        </tr>
                    </thead>
                    <tbody>
                        {groups.map(group => (
                            <tr key={group.group_id}>
                                <td>{group.group_id}</td>
                                <td>{group.name}</td>
                                <td>{group.active == 1 ? 'Sim' : 'Não'}</td>
                                <td>
                                    <button className="edit-button" onClick={() => { setCurrentGroup(group); setAddingGroup(false); setShowModal(true); }}>Alterar</button>
                                    <button disabled={group.group_id === 'admin'} className="delete-button" onClick={() => handleDeleteGroup(group.group_id)}>Excluir</button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            )}

            {showModal && (
                <div className="modal show" style={{ display: 'block' }}>
                    <div className="modal-dialog">
                        <div className="modal-content">
                            <div className="modal-header">
                                <h5 className="modal-title">{currentGroup.group_id ? 'Editar' : 'Incluir'}</h5>
                            </div>
                            <div className="modal-body">
                                <form>
                                    <div className="form-group">
                                        <label>Group ID</label>
                                        <input disabled={!addingGroup} type="text" className="form-control" value={currentGroup.group_id} onChange={(e) => setCurrentGroup({ ...currentGroup, group_id: e.target.value })} />
                                    </div>
                                    <div className="form-group">
                                        <label>Name</label>
                                        <input type="text" className="form-control" value={currentGroup.name} onChange={(e) => setCurrentGroup({ ...currentGroup, name: e.target.value })} />
                                    </div>
                                    <div className="form-group">
                                        <label>Active</label>
                                        <input type="checkbox" checked={currentGroup.active == 1} onChange={(e) => setCurrentGroup({ ...currentGroup, active: e.target.checked ? 1 : 0 })} />
                                    </div>
                                </form>
                            </div>
                            <div className="modal-footer">
                                <button type="button" className="add-user-button" onClick={handleSaveGroup}>Gravar</button>
                                <button type="button" className="add-user-button" onClick={() => setShowModal(false)}>Fechar</button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
            <ConfirmationModal
                isOpen={isModalConfirmationOpen}
                title="Confirmação Operação?"
                message=""
                onConfirm={confirmAction}
                onCancel={cancelAction}
            />
        </div>
    );
};

export default GroupsManagement;