import React, { useEffect, useState, useCallback } from 'react';
import ConfirmationModal from "../ConfirmationModal/ConfirmationModal";
import axios from 'axios';
import './Services.css';
import Log from '../Log/Log';
import PatchApplyForm from '../PatchApplyForm/PatchApplyForm'; // Import the PatchApplyForm component
import Environments from '../Environments/Environments'; // Import the PatchApplyForm component
import DownloadFile from '../DownloadFile/DownloadFile'; // Import the PatchApplyForm component

export interface Service {
  Name: string;
  DisplayName: string;
  Status: string;
}

export interface logParams {
  serviceName: string;
  action: string;
  origin?: string;
  destination?: string;
  origin_tenant?: string;
  destination_tenant?: string;
  log_result?: string;
}

export interface ServicesProps {
  selectedTenantId: string | null;
  selectedTenantName: string | null;
}

export interface PatchApplyFormProps {
  tenants: any[];
  onClose: () => void;

}

const Services: React.FC<ServicesProps> = ({ selectedTenantId, selectedTenantName }) => {
  const [services, setServices] = useState<Service[]>([]);
  const [tenants, setTenants] = useState<any[]>([]); // Initialize as an empty array
  const [logMessages, setLogMessages] = useState<string[]>([]);
  const [showLog, setShowLog] = useState<boolean>(false);
  const [isLoadingService, setIsLoadingService] = useState<string | null>(null);
  const [showBalloon, setShowBalloon] = useState<boolean>(false);
  const [showWait, setShowWait] = useState<boolean>(false);
  const [originEnvironments, setOriginEnvironments] = useState<string[]>([]);
  const [destinationEnvironments, setDestinationEnvironments] = useState<string[]>([]);
  const [originTenantId, setOriginTenantId] = useState<string>('');
  const [destinationTenantId, setDestinationTenantId] = useState<string>('');
  const [originEnv, setOriginEnv] = useState<string>('');
  const [destEnv, setDestEnv] = useState<string>('');
  const [showRpoDialog, setShowRpoDialog] = useState<boolean>(false);
  const [selectedService, setSelectedService] = useState<string | null>(null);
  const [selectedActions, setSelectedActions] = useState<{ [key: string]: string }>({});
  const [showPatchDialog, setShowPatchDialog] = useState<boolean>(false); // For Apply Patch
  const [showEnvironments, setShowEnvironments] = useState<boolean>(false); // For Environments
  const [showDownloadFile, setShowDownloadFile] = useState<boolean>(false); // For DownloadFile

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalAction, setModalAction] = useState<() => void>(() => { });
  const [allowExclusiveMode, setExclusiveMode] = useState(true);


  const openModal = (action: () => void) => {
    setModalAction(() => action);
    setIsModalOpen(true);
  };

  const confirmAction = () => {
    if (modalAction) modalAction();
    setIsModalOpen(false);
  };

  const cancelAction = () => {
    setIsModalOpen(false);
  };

  const getBaseUrl = () => {
    return ''; // Adjust this according to your backend server setup
  };
  // Fetch services for the selected tenant
  const fetchServices = useCallback(async () => {
    if (!selectedTenantId) return; // If no tenant is selected, do nothing
    try {
      const response = await axios.get<Service[]>(`${getBaseUrl()}/api/get-services/${selectedTenantId}`);
      setServices(response.data);
      fetchExclusiveMode();
    } catch (error) {
      console.error('Error fetching services:', error);
    }
  }, [selectedTenantId]);

  useEffect(() => {
    const checkFiles = async () => {
      if (!selectedTenantId) return;
      try {
        const response = await axios.get(`${getBaseUrl()}/api/list-files/${selectedTenantId}`);
        if (response.data.length === 0) {
          document.querySelector('.action-buttons-artefatos')?.classList.add('hidden');
        } else {
          document.querySelector('.action-buttons-artefatos')?.classList.remove('hidden');
        }
      } catch (error) {
        console.error('Error checking files:', error);
      }
    };

    checkFiles();
  }, [selectedTenantId]);

  const fetchExclusiveMode = async () => {
    try {
      const response = await axios.get(`/api/exclusive-mode/${selectedTenantId}`);
      const exclusiveMode = response.data.exclusive_mode;
      setExclusiveMode(!exclusiveMode);
    } catch (error) {
      console.error('Error fetching exclusive mode:', error);
    }
  };

  useEffect(() => {
    const intervalId = setInterval(fetchServices, 10000); // Schedule fetchServices to run every 15 seconds
    return () => clearInterval(intervalId); // Cleanup interval on component unmount
  }, [fetchServices]);

  // Fetch tenants
  const fetchTenants = useCallback(async () => {
    try {
      const response = await axios.get(`${getBaseUrl()}/api/get-tenants`);
      // console.log('Fetched tenants:', response.data);
      if (Array.isArray(response.data)) {
        // Response is an array
        setTenants(response.data);
      } else if (Array.isArray(response.data.tenants)) {
        // Response is an object with a 'tenants' array
        setTenants(response.data.tenants);
      } else {
        console.error('Unexpected response format:', response.data);
        setTenants([]);
      }
    } catch (error) {
      console.error('Error fetching tenants:', error);
    }
  }, []);

  // Fetch environments for a specific tenant
  const fetchEnvironmentsForTenant = useCallback(
    async (tenantId: string, type: 'origin' | 'destination') => {
      if (!tenantId) return;
      try {
        const response = await axios.get<{ environments: string[] }>(`${getBaseUrl()}/api/get-environments/${tenantId}`);
        if (type === 'origin') {
          setOriginEnvironments(response.data.environments || []);
        } else {
          setDestinationEnvironments(response.data.environments || []);
        }
      } catch (error) {
        console.error('Error fetching environments:', error);
      }
    },
    []
  );

  useEffect(() => {
    fetchServices();
    fetchTenants();
  }, [fetchServices, fetchTenants]);

  const addLogMessage = (message: string) => {
    setLogMessages((prevMessages) => [...prevMessages, message]);
  };

  // Function to create a new log entry
  const createLogEntry = async (params: logParams) => {
    try {
      const originTenantName = tenants.find(tenant => tenant.id === params.origin_tenant)?.name || '';
      const destinationTenantName = tenants.find(tenant => tenant.id === params.destination_tenant)?.name || '';

      const now = new Date();
      const logEntry = {
        date: now.toISOString().split('T')[0],
        time: now.toTimeString().split(' ')[0],
        user: localStorage.getItem('username') || 'unknown', // Assuming you store username in localStorage
        tenant: selectedTenantName || 'unknown',
        service: params.serviceName,
        action: params.action,
        origin: params.origin || '',
        origin_tenant: originTenantName || '',
        destination_tenant: destinationTenantName || '',
        destination: params.destination || '',
        result: 'In Progress',
        log_result: params.log_result
      };
      const response = await axios.post(`${getBaseUrl()}/api/logs`, logEntry);
      return response.data.id; // Assuming the response includes the log ID
    } catch (error) {
      console.error('Error creating log entry:', error);
      return null;
    }
  };

  // Function to update the log entry with the finish time and result
  const updateLogEntry = async (logId: number, result: string, full_log?: string) => {
    try {
      const now = new Date();
      await axios.put(`${getBaseUrl()}/api/logs/${logId}`, {
        finish_date: now.toISOString().split('T')[0],
        finish_time: now.toLocaleTimeString('en-US', { hour12: false }),
        result: result,
        log_result: full_log
      });
    } catch (error) {
      console.error('Error updating log entry:', error);
    }
  };

  const executeServiceAction = async (serviceName: string, action: 'start' | 'stop' | 'restart') => {
    setIsLoadingService(serviceName);
    setSelectedService(null);

    setSelectedActions((prevActions) => ({
      ...prevActions,
      [serviceName]: '', // Reset the selected action to default
    }));

    setServices((prevServices) =>
      prevServices.map((service) =>
        service.Name === serviceName ? { ...service, Status: 'Updating' } : service
      )
    );

    const logId = await createLogEntry({ serviceName: serviceName, action: `${action} service` } as logParams);

    try {
      await axios.post(`${getBaseUrl()}/api/${action}-service`, { serviceName });
      addLogMessage(`Service ${serviceName} ${action}ed successfully.`);
      fetchServices();
      setShowBalloon(true); // Show green balloon
      setTimeout(() => setShowBalloon(false), 3000); // Hide after 3 seconds
      if (logId) await updateLogEntry(logId, 'Success');
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      addLogMessage(`Error ${action}ing service ${serviceName}: ${errorMessage}`);
      console.error(`Error ${action}ing service:`, error);
      if (logId) await updateLogEntry(logId, 'Failed', errorMessage);
    } finally {
      setIsLoadingService(null);
    }
  };

  const handleExclusiveAction = async (action: 'on' | 'off') => {
    const logId = await createLogEntry({ serviceName: 'Exclusive Mode', action: `Set exclusive mode ${action}` } as logParams);
    setServices((prevServices) =>
      prevServices.map((service) => ({ ...service, Status: 'Updating' }))
    );

    try {
      await axios.post(`${getBaseUrl()}/api/exclusive-mode-${action}/${selectedTenantId}`);
      addLogMessage(`Exclusive Mode Activated successfully.`);
      fetchServices();
      setShowBalloon(true); // Show green balloon
      setTimeout(() => setShowBalloon(false), 3000); // Hide after 3 seconds
      if (logId) await updateLogEntry(logId, 'Success');
      setExclusiveMode(action === "on" ? false : true)
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      console.error(`Error in exclusive mode ${action}:`, error);
      if (logId) await updateLogEntry(logId, 'Failed', errorMessage);
    }
  };

  const handleBulkAction = async (action: 'start-all' | 'stop-all' | 'restart-all') => {
    const logId = await createLogEntry({ serviceName: 'Bulk Action', action: action.replace('-', ' ') } as logParams);
    setServices((prevServices) =>
      prevServices.map((service) => ({ ...service, Status: 'Updating' }))
    );

    try {
      await axios.post(`${getBaseUrl()}/api/${action}/${selectedTenantId}`);
      addLogMessage(`${action.replace('-', ' ')} executed successfully.`);
      fetchServices(); // Refresh the services after the action is completed
      setShowBalloon(true); // Show green balloon
      setTimeout(() => setShowBalloon(false), 3000); // Hide after 3 seconds
      if (logId) await updateLogEntry(logId, 'Success');
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      console.error(`Error in bulk action: ${action}`, error);
      addLogMessage(`Error executing ${action}: ${error}`);
      if (logId) await updateLogEntry(logId, 'Failed', errorMessage);
    }
  };

  const promoteRpo = async () => {
    try {
      if (
        originTenantId &&
        originEnv &&
        destinationTenantId &&
        destEnv &&
        (originTenantId !== destinationTenantId || originEnv !== destEnv)
      ) {
        const promoteData = {
          origin_tenant: originTenantId,
          origin: originEnv,
          destination_tenant: destinationTenantId,
          destination: destEnv,
        };
        const logId = await createLogEntry({ serviceName: 'Promote RPO', action: 'Promote', origin: originEnv, destination: destEnv, origin_tenant: originTenantId, destination_tenant: destinationTenantId } as logParams);
        // Set all services to 'Updating' status
        setServices((prevServices) =>
          prevServices.map((service) => ({ ...service, Status: 'Updating' }))
        );

        try {
          setShowWait(true);
          await axios.post(`${getBaseUrl()}/api/promote`, promoteData);
          addLogMessage(
            `RPO promovido de ${originEnv} (Topologia ${originTenantId}) para ${destEnv} (Topologia ${destinationTenantId}).`
          );
          if (logId) await updateLogEntry(logId, 'Success');
        } catch (error) {
          console.error('Error promoting RPO:', error);
          if (axios.isAxiosError(error) && error.response?.data?.error) {
            addLogMessage(`Error promoting RPO: ${error.response.data.error}`);
            if (logId) await updateLogEntry(logId, 'Failed', error.response.data.error);
          } else {
            addLogMessage(`Error promoting RPO: ${String(error)}`);
            if (logId) await updateLogEntry(logId, 'Failed', String(error));
          }
          setShowWait(false);
        } finally {
          // Fetch the updated services to return their status to the original content
          await fetchServices();
          setShowRpoDialog(false);
          setShowWait(false);
        }
        // Reset selections
        setOriginTenantId('');
        setOriginEnv('');
        setDestinationTenantId('');
        setDestEnv('');
      } else {
        addLogMessage('Topologias de origem e destino devem ser diferentes.');
      }
    } catch (error) {
      console.error('Error promoting RPO:', error);
    }
  };

  const getStatusColor = (status: string) => {
    if (status === 'Running') return 'green';
    if (status === 'Stopped') return 'red';
    if (status === 'Updating') return 'orange';
    return 'grey';
  };

  const downloadIniFile = async (serviceName: string) => {
    try {
      setShowWait(true); // Show the "wait" message while downloading the file
      const response = await axios.get(`${getBaseUrl()}/api/get-ini/${serviceName}`, {
        responseType: 'blob', // Important for downloading files
      });

      // Create a link element, use it to download the file, and then remove it
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `${serviceName}.ini`); // Or any other extension
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      setShowWait(false);
    } catch (error) {
      console.error('Error downloading ini file:', error);
      setShowWait(false);
    }
  };
  // Function to download the log file
  const downloadLog = async (serviceName: string) => {
    try {
      setShowWait(true); // Show the "wait" message while downloading the file
      const response = await axios.get(`${getBaseUrl()}/api/get-log/${serviceName}`, {
        responseType: 'blob', // Important for downloading files
      });

      // Create a link element, use it to download the file, and then remove it
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `${serviceName}.log`); // Or any other extension
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      setShowWait(true);
    } catch (error) {
      console.error('Error downloading log file:', error);
    }
    setShowWait(false);
  };

  return (
    <div className="services">
      <h2>Serviços {selectedTenantId ? ` - ${selectedTenantName} ` : ''}</h2>

      {showBalloon && <div className="success-balloon">Ação executada com sucesso!</div>}

      {showWait && <div className="success-balloon">Aguarde...</div>}

      <div className="content-wrapper">
        <div className="action-buttons-container">
          <div className="action-buttons">
            <button onClick={() => openModal(() => handleExclusiveAction(allowExclusiveMode ? "on" : "off"))}>
              {allowExclusiveMode ? "Ativar Exclusivo" : "Desativar Exclusivo"}
            </button>
            <button onClick={() => openModal(() => handleBulkAction('start-all'))}>Iniciar Todos</button>
            <button onClick={() => openModal(() => handleBulkAction('stop-all'))}>Parar Todos</button>
            <button onClick={() => openModal(() => handleBulkAction('restart-all'))}>Reiniciar</button>
            <button onClick={() => setShowRpoDialog(true)}>Promover RPO</button>
            <button onClick={() => setShowEnvironments(true)}>Ambientes</button>
            <button onClick={() => setShowDownloadFile(true)}>Artefatos</button>
            <button onClick={() => setShowPatchDialog(true)}>Aplicar Patch</button> {/* Apply Patch button */}
          </div>
        </div>

        {showPatchDialog && (
          <div className="patch-dialog">
            <PatchApplyForm tenants={tenants} onClose={() => setShowPatchDialog(false)} />
          </div>
        )}

        {showEnvironments && (
          <div className="Environments">
            <Environments tenants={tenants} onClose={() => setShowEnvironments(false)} />
          </div>
        )}

        {showDownloadFile && (
          <div className="DownloadFile">
            <DownloadFile tenantId={selectedTenantId} onClose={() => setShowDownloadFile(false)} />
          </div>
        )}

        {showRpoDialog && (
          <div className="overlay">
            <div className="rpo-dialog">
              <h3>Promover RPO</h3>
              <label>
                Topologia Origem:
                <select
                  value={originTenantId}
                  onChange={(e) => {
                    const selectedTenantId = e.target.value;
                    setOriginTenantId(selectedTenantId);
                    setOriginEnv(''); // Reset origin environment
                    fetchEnvironmentsForTenant(selectedTenantId, 'origin');
                  }}
                >
                  <option value="">Selecione</option>
                  {tenants.map((tenant) => (
                    <option key={tenant.id} value={tenant.id}>
                      {tenant.name}
                    </option>
                  ))}
                </select>
              </label>
              <label>
                RPO Origem:
                <select
                  value={originEnv}
                  onChange={(e) => setOriginEnv(e.target.value)}
                >
                  <option value="">Selecione</option>
                  {originEnvironments.map((environment, index) => (
                    <option key={index} value={environment}>
                      {environment}
                    </option>
                  ))}
                </select>
              </label>
              <label>
                Topologia Destino:
                <select
                  value={destinationTenantId}
                  onChange={(e) => {
                    const selectedTenantId = e.target.value;
                    setDestinationTenantId(selectedTenantId);
                    setDestEnv(''); // Reset destination environment
                    fetchEnvironmentsForTenant(selectedTenantId, 'destination');
                  }}
                >
                  <option value="">Selecione</option>
                  {tenants.map((tenant) => (
                    <option key={tenant.id} value={tenant.id}>
                      {tenant.name}
                    </option>
                  ))}
                </select>
              </label>
              <label>
                RPO Destino:
                <select
                  value={destEnv}
                  onChange={(e) => setDestEnv(e.target.value)}
                >
                  <option value="">Selecione</option>
                  {destinationEnvironments.map((environment, index) => (
                    <option key={index} value={environment}>
                      {environment}
                    </option>
                  ))}
                </select>
              </label>
              <div className="button-container">
                <button onClick={promoteRpo}>Executar</button>
                <button onClick={() => setShowRpoDialog(false)}>Cancelar</button>
              </div>
            </div>
          </div>
        )}
        <ConfirmationModal
          isOpen={isModalOpen}
          title="Confirmação Operação?"
          message=""
          onConfirm={confirmAction}
          onCancel={cancelAction}
        />
        <table className="services-table">
          <thead>
            <tr>
              <th>&nbsp;ID</th>
              <th>Status</th>
              <th>Nome</th>
              <th>Descrição</th>
              <th>Ações</th>
            </tr>
          </thead>
          <tbody>
            {services.map((service, index) => (
              <tr key={service.Name} className={index % 2 === 0 ? 'even-row' : 'odd-row'}>
                <td>{index + 1}</td>
                <td>
                  <span
                    className="status-indicator"
                    style={{ backgroundColor: getStatusColor(service.Status) }}
                  />
                  <span>{service.Status}</span>
                  <select
                    value={selectedActions[service.Name] || ''}
                    onChange={(e) => {
                      const action = e.target.value as 'start' | 'stop' | 'restart';
                      setSelectedActions((prevActions) => ({
                        ...prevActions,
                        [service.Name]: action,
                      }));
                      executeServiceAction(service.Name, action);
                    }}
                  >
                    <option value="" disabled>Ações</option>
                    <option value="restart">Reiniciar Serviço</option>
                    <option value="start">Iniciar Serviço</option>
                    <option value="stop">Parar Serviço</option>
                  </select>
                </td>
                <td>{service.Name}</td>
                <td>{service.DisplayName}</td>
                <td>
                  <select
                    onChange={(e) => {
                      const selectedOption = e.target.value;
                      if (selectedOption === 'log') {
                        downloadLog(service.Name);
                      } else if (selectedOption === 'ini') {
                        downloadIniFile(service.Name);
                      }
                      e.target.value = ''; // Reset to default option
                    }}
                    defaultValue=""
                  >
                    <option value="" disabled>Selecione uma opção</option>
                    <option value="log">Log</option>
                    <option value="ini">Arquivo .ini</option>
                  </select>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Services;