import React, { useEffect, useState } from 'react';
import axios from 'axios';
import styles from './DownloadFile.module.css'; // Import the CSS Module

interface DownloadFileProps {
  tenantId: string | null;
  onClose: () => void;
}

const getBaseUrl = () => {
  return ''; // Replace with your actual base URL
};

const DownloadFile: React.FC<DownloadFileProps> = ({ tenantId, onClose }) => {
  const [fileOptions, setFileOptions] = useState<{ value: string; label: string }[]>([]);
  const [selectedFiles, setSelectedFiles] = useState<Set<string>>(new Set());

  useEffect(() => {
    const fetchFiles = async () => {
      if (tenantId) {
        try {
          const response = await axios.get(`${getBaseUrl()}/api/list-files/${tenantId}`);
          const files = response.data;
          const options = files.map((file: { id: string; name: string }) => ({
            value: file.id,
            label: file.name,
          }));
          setFileOptions(options);
        } catch (error) {
          console.error('Error fetching files:', error);
        }
      }
    };

    fetchFiles();
  }, [tenantId]);

  const toggleFileSelection = (fileId: string) => {
    setSelectedFiles((prevSelected) => {
      const updatedSelection = new Set(prevSelected);
      if (updatedSelection.has(fileId)) {
        updatedSelection.delete(fileId);
      } else {
        updatedSelection.add(fileId);
      }
      return updatedSelection;
    });
  };

  const handleDownload = async () => {
    if (selectedFiles.size === 0) {
      alert('Please select at least one file to download.');
      return;
    }

    for (const fileId of selectedFiles) {
      try {
        const file = fileOptions.find((option) => option.value === fileId);
        if (!file) continue;

        const downloadResponse = await axios.get(`${getBaseUrl()}/api/download-file/${tenantId}/${fileId}`, {
          responseType: 'blob',
        });

        const url = window.URL.createObjectURL(new Blob([downloadResponse.data]));
        const link = document.createElement('a');
        link.href = url;
        link.setAttribute('download', file.label);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
      } catch (error) {
        console.error(`Error downloading file with ID ${fileId}:`, error);
      }
    }
  };

  return (
    <div className={styles.overlay}>

      <div className={styles.actions}>
        <button className={styles.button} type="button" onClick={handleDownload}>
          Download
        </button>
        <button className={styles.button} type="button" onClick={onClose}>
          Fechar
        </button>
      </div>

      <table className={styles.table}>
        <thead>
          <tr>
            <th>Select</th>
            <th>ID</th>
            <th>Name</th>
          </tr>
        </thead>
        <tbody>
          {fileOptions.map((file) => (
            <tr key={file.value}>
              <td>
                <input
                  type="checkbox"
                  checked={selectedFiles.has(file.value)}
                  onChange={() => toggleFileSelection(file.value)}
                />
              </td>
              <td>{file.value}</td>
              <td>{file.label}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default DownloadFile;
