import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './HeaderBar.css';
import socket, { Message } from "../.././socket";

interface HeaderBarProps {
  username: string;
}

const HeaderBar: React.FC<HeaderBarProps> = ({ username }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [fullName, setFullName] = useState('');
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  useEffect(() => {
    setSuccessMessage(null);

    // When the component mounts, set up Socket.IO listeners
    socket.on("connect", () => {
      console.log("Connected to the server via Socket.IO");
    });

    // Listen for incoming messages from the server
    const handleMessage = (message: Message) => {
      if (message.data.user_id && message.data.user_id !== username) {
      setMessages((prevMessages) => [...prevMessages, message]);
      setSuccessMessage(`${message.data.user_id} : ${message.data.content}`);
      setTimeout(() => setSuccessMessage(''), 10000); // Hide after 3 seconds
      }
    };

    socket.on("alert", handleMessage);
    socket.on("forum", handleMessage);
    socket.on("connect_error", (error) => {
      console.error("Connection error:", error);
    });

    // Clean up listeners on unmount
    return () => {
      socket.off("connect");
      socket.off("connect_error");
    };
  }, []);

  useEffect(() => {
    const fetchFullName = async () => {
      try {
        const response = await axios.get(`/api/users/${username}`);
        setFullName(response.data.name);
      } catch (error) {
        console.error('Error fetching user info:', error);
      }
    };

    fetchFullName();
  }, [username]);

  return (
    <div className="header-bar">
      {localStorage.getItem('tenant_logo') && localStorage.getItem('tenant_logo') !== 'null' && (
        <div className="header-logo-container">
          <img
            src={`data:image/png;base64,${localStorage.getItem('tenant_logo')}`}
            alt="logo"
            className="header-logo"
            style={{ width: '110px', height: 'auto', marginLeft: '20px' }}
          />
        </div>
      )}
      <div className="app-client"><h4>{localStorage.getItem('tenant_name') || ''}</h4></div>
      <div className="config-menu">
        {successMessage && <div className='trayMessageStyle'>{successMessage}</div>}
        <button className="config-button">{fullName || username}</button>
        <div className="dropdown-content">
          <Link to="/">Sair</Link>
        </div>
      </div>
    </div>
  );
};

export default HeaderBar;